// Filter deals modified in last 4 hours (to catch newly moved deals)
// and check if bid invitation task was already created
const results = $input.first().json;
const deals = results.results || [];
const cutoff = new Date(Date.now() - 4 * 60 * 60 * 1000);

const newDeals = deals.filter(d => {
  const modified = new Date(d.properties.hs_lastmodifieddate);
  return modified > cutoff;
});

return newDeals.map(d => ({
  json: {
    deal_id: d.id,
    deal_name: d.properties.dealname,
    package_name: d.properties.package_name || '',
    tradescope: d.properties.tradescope || '',
    estimator: d.properties.estimator || 'Unassigned',
    modified: d.properties.hs_lastmodifieddate,
  }
}));

// Create task payload for each associated contact
const dealData = $('Filter Recently Moved Deals').first().json;
const contactResp = $input.first().json;
const contacts = contactResp.results || [];

const dueDate = new Date();
dueDate.setDate(dueDate.getDate() + 3);
const dueDateMs = dueDate.getTime();

if (contacts.length === 0) {
  return [{ json: { skip: true, deal_name: dealData.deal_name, reason: 'No contacts associated' } }];
}

return contacts.map(c => ({
  json: {
    contact_id: c.id,
    deal_id: dealData.deal_id,
    deal_name: dealData.deal_name,
    tradescope: dealData.tradescope,
    task_subject: `Bid Invitation: ${dealData.deal_name} — ${dealData.tradescope || dealData.package_name}`,
    task_body: `Bid package sent out. Follow up with sub to confirm receipt and interest. Estimator: ${dealData.estimator}.`,
    due_date_ms: dueDateMs,
  }
}));

const all = $input.all();
const created = all.filter(i => i.json.id).length;
const deals = [...new Set(all.map(i => i.json.deal_name || '?'))];
return [{ json: {
  message: `Bid tasks created: ${created} tasks for deals: ${deals.join(', ')}`,
  count: created,
}}];
